const payload = $input.first().json.body || $input.first().json;
const message = payload.message || payload;
const toolCalls = message.toolCallList || message.toolCalls || [];
const toolCall = toolCalls[0] || {};
const toolName = toolCall.function?.name || '';
const args = toolCall.function?.arguments || {};
const parsedArgs = typeof args === 'string' ? JSON.parse(args) : args;
const toolCallId = toolCall.id || '';

if (toolName === 'submit_escalation') {
  return [{
    json: {
      toolType: 'escalation',
      toolCallId,
      // Change: Use strict boolean check to ensure false is preserved
      isTest: parsedArgs.is_test === true, 
      userName: parsedArgs.user_name || '',
      userEmail: parsedArgs.user_email || '',
      preferredTime: parsedArgs.preferred_time || '',
      reason: parsedArgs.reason || ''
    }
  }];
}

// Default: answer_question
const userQuery = parsedArgs.question || '';

if (!userQuery || userQuery.trim().length < 3) {
  return [{
    json: {
      toolType: 'answer',
      toolCallId,
      // Optional: Add isTest here too if you log KB queries
      isTest: parsedArgs.is_test === true,
      userQuery: '',
      skipProcessing: true,
      response: "I didn't quite catch that. Could you please repeat your question?"
    }
  }];
}

return [{
  json: {
    toolType: 'answer',
    toolCallId,
    // Optional: Add isTest here too if you log KB queries
    isTest: parsedArgs.is_test === true,
    userQuery: userQuery.trim(),
    skipProcessing: false
  }
}];

const data = $('Extract Agent Answer').first().json;

return [{
  json: {
    toolCallId: data.toolCallId,
    response: data.response
  }
}];

