const agentOutput = $input.first().json;
const prevData = $('Extract & Validate Input').first().json;

const output = agentOutput.output || agentOutput.text || agentOutput.response || '';

// Try to extract JSON from <response> tags
const tagMatch = output.match(/<response>\s*([\s\S]*?)\s*<\/response>/);
let parsed;

if (tagMatch) {
  try {
    parsed = JSON.parse(tagMatch[1].trim());
  } catch {
    parsed = null;
  }
}

// If no tags found, try parsing the whole output as JSON
if (!parsed) {
  const jsonMatch = output.match(/\{[\s\S]*"action"[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch {
      parsed = null;
    }
  }
}

// If still can't parse, treat the whole output as a direct answer
if (!parsed) {
  parsed = {
    action: 'direct_answer',
    message: output
  };
}

return [{
  json: {
    toolCallId: prevData.toolCallId,
    action: parsed.action || 'direct_answer',
    response: parsed.message || output
  }
}];

const input = $input.first().json;
const prevData = $('Extract & Validate Input').first().json;

const responseText = input.output?.[0]?.content?.[0]?.text 
  || input.text 
  || input.message?.content 
  || JSON.stringify(input);

const clean = responseText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

let result;
try {
  result = JSON.parse(clean);
} catch {
  result = { escalate: true, reason: "Could not parse escalation check — defaulting to escalate" };
}

return [{
  json: {
    userQuery: prevData.userQuery,
    toolCallId: prevData.toolCallId,
    shouldEscalate: result.escalate || false,
    escalationReason: result.reason || ""
  }
}];

